GameAdvanced = {}

function GameAdvanced:onButtonClick(player, itemId)

    for _, Value in pairs(player.shopAdvanced) do
        if Value.id == itemId then
            if Value.status == Define.ItemBuyStatus.Unlock then
                self:onAdvancedBuy(player, itemId)
            elseif Value.status == Define.ItemBuyStatus.Buy then
                self:onAdvancedUsed(player, itemId)
            elseif Value.status == Define.ItemBuyStatus.Used then
                self:onAdvancedUnload(player, itemId)
            end
        end
    end
end

function GameAdvanced:onAdvancedBuy(player, itemId)

    local advanced = AdvancedConfig:getAdvancedConfig(itemId)
    if advanced ~= nil then

        if advanced.moneyType == Define.MoneyType.SLGolds then

            --减金币PlayerProperty:changeGold(goldNum)
            if player.property.gold >= BigNum.new(string.format("%f", advanced.price)) then
                player.property:changeGold(-advanced.price)
                self:onBuySuccess(player, itemId)
            else
                HostApi.sendCommonTip(player.rakssid, "gold_enough")
            end
        end

        if advanced.moneyType == Define.MoneyType.DiamondGolds2 then

            --PayHelper.payDiamonds(player.userId, advanced.id, advanced.price, function(player)
            --    self:onBuySuccess(player, itemId)
            --end, nil)

            PayHelper.payDiamondsSync(player.userId, advanced.id, advanced.price, function(player)
                self:onBuySuccess(player, itemId)
            end, nil)

        end

        if advanced.moneyType == Define.MoneyType.DiamondGolds1 then
            --PayHelper.payDiamonds(player.userId, advanced.id, advanced.price, function(player)
            --    self:onBuySuccess(player, itemId)
            --end, nil)
            PayHelper.payDiamondsSync(player.userId, advanced.id, advanced.price, function(player)
                self:onBuySuccess(player, itemId)
            end, nil)
        end

        ReportUtil.reportAdvancedBuy(player, itemId)
    end
end

function GameAdvanced:onBuySuccess(player, itemId)

    local data = {}
    for _, Value in pairs(player.shopAdvanced) do
        if Value.id == itemId then
            Value.status = Define.ItemBuyStatus.Buy
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end
    --print(" GameAdvanced:onBuySuccess(player, itemId)")
    --print(json.encode(player.shopAdvanced))

    ShopManager:senderAdvancedInfo(player, data)
end

function GameAdvanced:onAdvancedUsed(player, itemId)


    --print(" GameAdvanced:onAdvancedUsed(player, itemId)")
    --print(json.encode(player.shopAdvanced))
    SceneManager:joinAdvancedScene(player, itemId)

    ReportUtil.reportAdvancedUsed(player, itemId)
end

function GameAdvanced:onAdvancedUnload(player, itemId)

    local data = {}
    ShopManager:senderAdvancedInfo(player, data)

end

function GameAdvanced:updateAdvancedData(player)
    if not player then
        return
    end

    for _, setting in pairs(AdvancedConfig.settings) do
        local find = false
        for _, data in pairs(player.shopAdvanced) do
            if data.id == setting.id then
                find = true
                break
            end
        end

        if not find then
            table.insert(player.shopAdvanced, {
                id = setting.id,
                status = Define.ItemBuyStatus.Lock
            })
        end
    end

    for _, Value in pairs(player.shopAdvanced) do
        if Value.status == Define.ItemBuyStatus.Lock then
            local advanced = AdvancedConfig:getAdvancedConfig(Value.id)
            if advanced and self:canUnlock(advanced.unlock, player) then
                Value.status = Define.ItemBuyStatus.Unlock
            end
        end
    end
end

function GameAdvanced:canUnlock(unlock, player)
    if not player then
        return false
    end

    for _, Value in pairs(player.shopAdvanced) do
        if unlock == Value.id then
            return Value.status == Define.ItemBuyStatus.Used
        end
    end

    return false
end

function GameAdvanced:initAdvancedItem(player)
    if #player.shopAdvanced ~= 0 then
        self:updateAdvancedData(player)
        return
    end

    table.sort(AdvancedConfig.settings, function(a, b)
        return a.id < b.id
    end)

    local i = 1
    for _, Value in pairs(AdvancedConfig.settings) do
        if i == 1 then
            table.insert(player.shopAdvanced, {
                id = Value.id,
                status = Define.ItemBuyStatus.Unlock
            })
        else
            table.insert(player.shopAdvanced, {
                id = Value.id,
                status = Define.ItemBuyStatus.Lock
            })
        end
        i = i + 1
    end
end

function GameAdvanced:onFinishAdvanced(player, advancedId)
    if AdvancedConfig:getAdvancedConfig(advancedId) then
        player.property:changeAdvancedLevel(advancedId)
    end

    --肌肉量和金币清零
    player.property:changeGold(-player.property.gold)
    player.property:changeMuscleMass(-player.property.muscleMass)

    --基因和和器材归零
    GameTokenGene:initAdvancedGeneItem(player)
    GameGene:initAdvancedGeneItem(player)
    GameTokenFitnessEquip:initAdvancedFitnessEquipItem(player)
    GameFitnessEquip:initAdvancedFitnessEquipItem(player)

    --解锁技能
    GameSkill:initAdvancedSkillItem(player, advancedId)
    GameTokenSkill:initAdvancedSkillItem(player, advancedId)
    --更新排行榜
    LSRankManager:updatePlayerRank(player)

    local data = {}
    for _, Value in pairs(player.shopAdvanced) do
        if Value.id == advancedId then
            Value.status = Define.ItemBuyStatus.Used
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    for _, Value in pairs(player.shopAdvanced) do
        local advanced = AdvancedConfig:getAdvancedConfig(Value.id)
        if advanced and advanced.unlock == advancedId then
            Value.status = Define.ItemBuyStatus.Unlock
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    ShopManager:senderAdvancedInfo(player, data)
end

return GameAdvanced